html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Accessible Pagination</title>
    <link rel="stylesheet" href="styles.css">
</head>
<body>
    <nav class="max-w-md mx-auto py-4 bg-gray-200 rounded shadow-md">
        <button id="prev-button" class="py-2 px-4 font-bold text-gray-700 bg-white hover:bg-gray-100 rounded-l-full inline-block">Prev</button>
        <button id="next-button" class="py-2 px-4 font-bold text-gray-700 bg-white hover:bg-gray-100 rounded-r-full inline-block">Next</button>
        <ul id="pagination-list" class="flex justify-between items-center p-2 list-none bg-white rounded"></ul>
    </nav>
    <script src="script.js"></script>
</body>
</html>

<script src="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.js"></script>
css: .pagination-list li {
    @apply font-bold text-gray-700 bg-white hover:bg-gray-100 rounded-full inline-block py-2 px-4;
}
.pagination-list li:hover {
    @apply bg-blue-500 text-white;
}
.pagination-list li:active {
    @apply bg-blue-700;
}
#prev-button {
    @apply rounded-l-full;
}
#next-button {
    @apply rounded-r-full;
}
js: function Pagination() {
    this.currentPage = 1;
    this.pages = 10;
}

const pagination = new Pagination();

const prevButton = document.getElementById('prev-button');
const nextButton = document.getElementById('next-button');
const paginationList = document.getElementById('pagination-list');

prevButton.addEventListener('click', () => {
    if (pagination.currentPage > 1) {
        pagination.currentPage--;
        updatePagination();
    }
});

nextButton.addEventListener('click', () => {
    if (pagination.currentPage < pagination.pages) {
        pagination.currentPage++;
        updatePagination();
    }
});

function updatePagination() {
    paginationList.innerHTML = '';
    for (let i = 1; i <= pagination.pages; i++) {
        if (i === pagination.currentPage) {
            const currentPageItem = document.createElement('li');
            currentPageItem.textContent = pagination.currentPage;
            currentPageItem.classList.add('active');
            paginationList.appendChild(currentPageItem);
        } else {
            const paginationItem = document.createElement('li');
            paginationItem.textContent = i;
            paginationList.appendChild(paginationItem);
        }
    }
}

updatePagination();
